+import type { AnyColumn } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { Column } from '~/column.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+export type WindowOrderBy = SQLWrapper;
+export type WindowBoundary =
+	| { readonly kind: 'unbounded preceding' }
+	| { readonly kind: 'current row' }
+	| { readonly kind: 'unbounded following' }
+	| { readonly kind: 'preceding'; readonly value: number }
+	| { readonly kind: 'following'; readonly value: number };
+
+export const unboundedPreceding: WindowBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowBoundary = { kind: 'unbounded following' };
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	return { kind: name, value };
+}
+
+export function preceding(value: number): WindowBoundary { return positionalBoundary('preceding', value); }
+export function following(value: number): WindowBoundary { return positionalBoundary('following', value); }
+
+export interface WindowFrame { readonly type: 'rows' | 'range'; readonly from: WindowBoundary; readonly to: WindowBoundary; }
+export interface WindowSpec { partitionBy?: SQLWrapper | SQLWrapper[]; orderBy?: WindowOrderBy | WindowOrderBy[]; frame?: WindowFrame; }
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame { return frame('rows', spec); }
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame { return frame('range', spec); }
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	return boundary.kind === 'preceding' || boundary.kind === 'following'
+		? sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.kind)}`
+		: sql.raw(boundary.kind);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	const partitionSql = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderSql = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame ? sql`${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}` : undefined;
+	return sql.join([partitionSql, orderSql, frameSql].filter((x): x is SQL => x !== undefined), sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+	getSQL(): SQL<T> { return this.expression; }
+}
+
+function window<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+function positiveInteger(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+}
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TData> ? TData : unknown;
+
+export const rowNumber = (): WindowFunction<number> => window('row_number');
+export const rank = (): WindowFunction<number> => window('rank');
+export const denseRank = (): WindowFunction<number> => window('dense_rank');
+export function ntile(buckets: number): WindowFunction<number> { positiveInteger('ntile', buckets); return window('ntile', [sql.raw(String(buckets))]); }
+export const percentRank = (): WindowFunction<number> => window('percent_rank');
+export const cumeDist = (): WindowFunction<number> => window('cume_dist');
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper, D extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: D): WindowFunction<Exclude<ExpressionData<T>, null> | ExpressionData<D>>;
+export function lag(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<any> { return window('lag', [value, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: SQLWrapper): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper, D extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: D): WindowFunction<Exclude<ExpressionData<T>, null> | ExpressionData<D>>;
+export function lead(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<any> { return window('lead', [value, ...(offset === undefined ? [] : [sql.raw(String(offset))]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export const firstValue = <T extends SQLWrapper>(value: T): WindowFunction<ExpressionData<T> | null> => window('first_value', [value]);
+export const lastValue = <T extends SQLWrapper>(value: T): WindowFunction<ExpressionData<T> | null> => window('last_value', [value]);
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowFunction<ExpressionData<T> | null> { positiveInteger('nthValue', nth); return window('nth_value', [value, sql.raw(String(nth))]); }
+export const windowSum = <T extends SQLWrapper>(value: T): WindowFunction<string | null> => window('sum', [value]);
+export const windowAvg = <T extends SQLWrapper>(value: T): WindowFunction<string | null> => window('avg', [value]);
+export const windowMin = <T extends SQLWrapper>(value: T): WindowFunction<(ExpressionData<T>) | null> => window('min', [value]);
+export const windowMax = <T extends SQLWrapper>(value: T): WindowFunction<(ExpressionData<T>) | null> => window('max', [value]);
+export const windowCount = (value?: SQLWrapper): WindowFunction<number> => window('count', [value ?? sql.raw('*')]);
